  ('shatavari', 'Shatavari', 'Shatavari / Asparagus racemosus', 'Asparagus racemosus, Wilder Spargel, Satavar, Satavari, Satmuli, Frau mit 100 Ehemannern', 'Adaptogene', 'Frauengesundheit / Hormone', 'Ayurvedisches Rasayana (Verjuengungsmittel) fuer Frauen aus der Wurzel des wilden Spargels. Enthaelt Steroidsaponine (Shatavarine I-X), Isoflavone und Phytooestrogene. STAERKSTE EVIDENZ bei Menopause-Symptomen (5-7 RCTs). Moderate Evidenz als Galaktagogum (Milchbildung). ACHTUNG: KEINE Humanstudien zu PCOS/Fertilitaet trotz populaerer Behauptungen! EU-REGULATORIK: Wahrscheinlich NOVEL FOOD - vor Markteinführung pruefen!', 'Menopause, Phytooestrogen, Galaktagogum, Adaptogen', 'Menopause-Symptome, Hitzewallungen, Laktationsinsuffizienz (begrenzte Evidenz)', 'KEINE - Health Claims nicht zugelassen', 'Mit Milch oder Wasser; traditionell mit Ghee', 'Milch, Ghee (traditionell ayurvedisch)', '-', 'ACHTUNG: Wahrscheinlich Novel Food in EU! Phytooestrogengehalt beachten!', '500 mg standardisierter Extrakt oder 3-6 g Pulver', 'ashwagandha, triphala, brahmi', 'lithium (moderate Interaktion)', '-', 'Klassische Kombination mit Ashwagandha fuer Frauen', 'Nein', 'Ja', 'Ja', 'Ja', 'NICHT SICHER - Teratogenitaet in Tierstudien!', 'MOEGLICHERWEISE SICHER - als Galaktagogum verwendet, aber Langzeitdaten fehlen', 'KEINE DATEN', 'Gut untersucht bei perimenopausalen Frauen (40-50 Jahre)', 'Standardisierung auf Shatavarin IV (>=0,1%) oder Gesamtsaponine (>=10%)', 'Steroidsaponine gut absorbiert; mit Fett (Ghee/Milch) verbessert', 'Standardisierter Wurzelextrakt (200-500 mg/Tag) oder Churna (Pulver) 3-6 g/Tag', 'Trocken, lichtgeschuetzt', '24-36', 'Phytooestrogene Wirkung - KONTRAINDIZIERT bei hormonabhaengigen Tumoren! Lithium-Interaktion! Wahrscheinlich Novel Food in EU!', 'Hormonabhaengige Tumoren (Brust, Uterus, Ovarien), Lithium-Therapie, Schwangerschaft', 'Blaehungen, lockerer Stuhl, Uebelkeit, Kopfschmerzen (bei >6 g/Tag)', 'Nicht dokumentiert bei ueblichen Dosen', 'Nein - ausser bei Lithium-Therapie', 'Lithiumspiegel (bei Lithium-Therapie)', 'Lithium: 0,6-1,2 mmol/L', 'Wurzelknollen; wild: Indien, Nepal, Sri Lanka, Himalaya - ART IST GEFAEHRDET!', 'NICHT DEFINIERT', 'mg', 'NICHT DEFINIERT', 'mg', 'NICHT DEFINIERT', 'Studiendosis Menopause: 200 mg/Tag standardisierter Extrakt (120 Tage)', '2025-12-24', 'VERIFIZIERT'),
  ('acai', 'Acai', 'Acai / Euterpe oleracea', 'Euterpe oleracea, Acai-Palme, Kohlpalme, Amazonas-Beere, Acai Berry', 'Superfoods', 'Antioxidantien', 'Frucht der Acai-Palme aus dem Amazonas mit hohem Anthocyangehalt (Cyanidin-3-rutinosid, Cyanidin-3-glucosid). Antioxidative Wirkung im Plasma nachgewiesen. KRITISCH: KEINE EVIDENZ fuer Gewichtsverlust trotz massiver Marketing-Behauptungen! FTC hat Millionenstrafen wegen Betrug verhaengt. ORAC-Wert von USDA 2012 als irrelevant zurueckgezogen. Hoher Fettgehalt (50% TG) mit olivenoel-aehnlichem Profil. CHAGAS-RISIKO bei unpasteurisierten Produkten!', 'Anthocyane, Antioxidans, Polyphenole', 'Antioxidation (nachgewiesen); Gewichtsverlust (NICHT BELEGT!)', 'KEINE - Health Claims nicht zugelassen; Antioxidans-Claims abgelehnt', 'Mit oder ohne Mahlzeit', '-', '-', 'ORAC-Werte sind wissenschaftlich irrelevant! Gewichtsverlust-Claims sind Betrug!', '200 g Fruchtfleisch oder 200 mL Saft', 'andere Beeren, vitamin-c', '-', '-', 'Traditionell im Amazonas mit Maniokmehl zu herzhaften Gerichten', 'Ja (hoher Fettgehalt!)', 'Teilweise (Anthocyane)', 'Ja', 'Ja', 'Wahrscheinlich sicher als Lebensmittel; keine Supplementdaten', 'Wahrscheinlich sicher als Lebensmittel', 'Als Lebensmittel akzeptabel', 'Keine besonderen Hinweise', 'Anthocyangehalt deklariert (mg C3G-Aequivalente); pasteurisiert (Chagas!); 450-fache Qualitaetsunterschiede dokumentiert!', 'Anthocyane: Cmax 2321 ng/L, Tmax 2,2 h; Bioverfuegbarkeit <5%', 'Gefriergetrocknetes Pulver (hoechster Anthocyangehalt) oder pasteurisierter Saft', 'Gekuehlt oder gefroren; lichtgeschuetzt', '12-24 (Pulver); wenige Tage (frisch)', 'CHAGAS-KRANKHEIT: T. cruzi in 10% kommerzieller Produkte nachgewiesen! Nur pasteurisierte Produkte verwenden! GEWICHTSVERLUST-CLAIMS SIND BETRUG - FTC-Strafen >$25 Mio!', 'Palmenallergie, unpasteurisierte Produkte (Chagas-Risiko)', 'Allergische Reaktionen (selten); GI-Beschwerden', 'Nicht dokumentiert', 'Nein', '-', '-', 'Acai-Palme (Euterpe oleracea); Amazonas-Becken, v.a. Para (Brasilien)', 'NICHT DEFINIERT', 'g oder mL', 'NICHT DEFINIERT', 'g', 'NICHT DEFINIERT', 'Studiendosis: 100-200 g Fruchtfleisch oder 200 mL Saft/Tag', '2025-12-24', 'VERIFIZIERT')
INSERT INTO supplements_basis (id, name, name_en, auch_bekannt_als, kategorie, unterkategorie, wirkung, wirkung_kurz, symptome_ziele, health_claims_efsa, einnahme_zeitpunkt, einnahme_mit, einnahme_ohne, einnahme_hinweis, max_einzeldosis, kombiniert_gut_mit, nicht_zusammen_mit, zeitlicher_abstand_h, kombinations_hinweis, fettloeslich, wasserloeslich, vegan_verfuegbar, halalzertifiziert_moeglich, schwangerschaft, stillzeit, kinder_geeignet, senioren_hinweis, qualitaetsmerkmale, bioverfuegbarkeit_info, beste_form, lagerung, haltbarkeit_monate, warnhinweise, kontraindikationen, nebenwirkungen_ueberdosis, ueberdosis_symptome, bluttest_empfohlen, welcher_blutwert, optimalbereich, natuerliche_quellen, rda_erwachsene, rda_einheit, ul_efsa, ul_einheit, bfr_hoechstmenge, dge_referenz, letzte_aktualisierung, verifiziert) VALUES
  ('epimedium', 'Epimedium (Horny Goat Weed)', 'Epimedium / Horny Goat Weed / Yin Yang Huo', 'Horny Goat Weed, Yin Yang Huo (淫羊藿), Elfenblume, Barrenwort, Fairy Wings, Bishop''s Hat, Icariin (Hauptwirkstoff), Herba Epimedii', 'Pflanzliche Extrakte', 'Sexualfunktion / Aphrodisiakum', '⚠️ MARKETING vs. EVIDENZ! PDE5-Hemmung durch Icariin nachgewiesen, ABER 80-100× schwächer als Sildenafil (IC50: 1-6 µM vs. 4-74 nM). Aktiver Metabolit Icariside II potenter (~50% von Sildenafil). Orale Bioverfügbarkeit NUR 0,1%! eNOS-Aktivierung → NO↑. Östrogenrezeptor-Modulation (SERM-ähnlich). ⚠️ KEINE Human-RCTs für ED! Einzige moderate Evidenz: Knochengesundheit (Zhang 2007).', '⚠️ Schwache PDE5-Hemmung, SERM-Aktivität, 0,1% Bioverfügbarkeit', '⚠️ KEINE EVIDENZ für: ED, Libido, Testosteron. MODERATE EVIDENZ: Knochengesundheit (postmenopausal). Traditionell (TCM): Nieren-Yang-Mangel, Impotenz, Knochen-/Sehnenprobleme.', '❌ KEINE EFSA Health Claims! ❌ KEINE EMA-Monographie! ❌ Extrakt = NOVEL FOOD (nicht zugelassen)!', 'Mit Mahlzeiten (verbessert Absorption minimal)', 'Fetthaltige Mahlzeit (Flavonoide)', '❌❌ NIEMALS mit PDE5-Hemmern! ❌❌ NIEMALS mit Nitraten!', '⚠️ Wirkung sehr fraglich wegen 0,1% Bioverfügbarkeit! Studiendosen: 60 mg Icariin/Tag für Knochen (Zhang 2007). TCM: 6-12 g Droge als Dekokt.', '500 mg Extrakt / 60 mg Icariin', 'Calcium, Vitamin D (Knochengesundheit)', '❌❌ PDE5-Hemmer (Sildenafil, Tadalafil)! ❌❌ Nitrate! ❌ Antikoagulantien! ❌ Aromatasehemmer!', '24+ h zu PDE5-Hemmern/Nitraten', '❌❌ KRITISCH: Kombination mit PDE5-Hemmern oder Nitraten kann lebensbedrohliche Hypotonie verursachen! Fallbericht: Arrhythmie bei CHF-Patient unter Sildenafil+Epimedium (PMID 15546831).', 'Teilweise (Flavonoide)', 'Teilweise', 'Ja', 'Ja', '❌❌ KONTRAINDIZIERT! Möglicherweise unsicher. Östrogene Wirkung.', '❌ Nicht empfohlen (keine Sicherheitsdaten)', '❌ Nicht empfohlen', '⚠️ VORSICHT bei kardiovaskulären Erkrankungen! Arrhythmie-Fallbericht bei 66-jährigem CHF-Patient.', '⚠️⚠️ KRITISCH: 81% der Produkte mit synthetischen PDE5-Hemmern verfälscht! Nur von vertrauenswürdigen Herstellern mit Drittlabor-Tests kaufen. Icariin-Standardisierung prüfen (≥5% Gesamtflavonoide laut PhChina).', '⚠️ EXTREM NIEDRIG! Icariin: nur 0,1% oral bioverfügbar! Icariside II (aktiver Metabolit): 4,1%. 91,2% Umwandlung zu Icariside II durch Darmbakterien.', 'Standardisierter Extrakt mit definiertem Icariin-Gehalt (20-60%). ABER: Wirksamkeit fraglich wegen Bioverfügbarkeit.', 'Kühl, trocken, lichtgeschützt', '24', '❌❌ LEBENSBEDROHLICH mit Nitraten! ❌❌ Arrhythmie-Risiko bei Herzerkrankungen! ⚠️ 81% Produkte verfälscht mit Sildenafil/Tadalafil! ⚠️ Hepatotoxizität möglich (124 Fälle 2012-2016). ⚠️ Blutungsrisiko. ⚠️ FÖRDERT Aromatase (nicht hemmt!).', '❌❌ Herzerkrankungen! ❌❌ Nitrat-Therapie! ❌❌ PDE5-Hemmer-Einnahme! ❌ Hormonempfindliche Tumoren! ❌ Schwangerschaft! ❌ Blutungsstörungen! ❌ Hypotonie!', 'Tachyarrhythmie, Hypomanie (Fallbericht), schwere Muskelspasmen, Hypotonie, Schwindel, Kopfschmerzen, GI-Beschwerden, Mundtrockenheit, Nasenbluten, allergische Dermatitis.', 'Atembeschwerden, Atemversagen (bei hohen Dosen), schwere Hypotonie, Arrhythmien', 'Bei Langzeitanwendung: Leberwerte', 'ALT, AST, GGT', 'Leberwerte im Normbereich', 'Blätter von Epimedium brevicornu, E. sagittatum, E. koreanum, E. pubescens, E. wushanense. Herkunft: China, Korea, Japan.', '-', '-', '-', '-', '-', '-', '2025-12-24', 'VERIFIZIERT'),
  ('kakaoextrakt', 'Kakaoextrakt (Flavanole)', 'Cocoa Extract (Flavanols)', 'Theobroma cacao, Kakaoflavanole, Cocoa Flavanols, Epicatechin, Kakao-Polyphenole, Cacao', 'Polyphenole', 'Kardiovaskulär, Endothelfunktion, Kognition', '✅ EFSA HEALTH CLAIM ZUGELASSEN: "Kakaoflavanole helfen, die Elastizität der Blutgefäße zu erhalten, was zu einem normalen Blutfluss beiträgt" (VO 851/2013). Hauptwirkstoff (-)-Epicatechin (35% der Polyphenole) aktiviert eNOS → NO-Produktion → Vasodilatation. COSMOS-Studie (PMID 35294962, n=21.442): 27% Reduktion kardiovaskulärer Todesfälle. Meta-Analysen: Blutdruck -1,8/-1,8 mmHg, FMD +1,17%, LDL -5,9 mg/dL.', '✅ EFSA-Claim (Gefäßelastizität); ✅ Blutdruck (moderat); ✅ Endothelfunktion; ⚠️ Kognition (kurzfristig)', 'Kardiovaskuläre Prävention, Bluthochdruck (mild), Endothelfunktion, kognitive Unterstützung', '✅ ZUGELASSEN: "Kakaoflavanole helfen, die Elastizität der Blutgefäße zu erhalten, was zu einem normalen Blutfluss beiträgt." Bedingung: Mind. 200 mg Flavanole/Tag. ❌ Abgelehnt: Antioxidativ, Blutdruck, Kognition.', 'Mit einer Mahlzeit (Fett verbessert Absorption). Kann morgens oder nachmittags eingenommen werden.', 'Mit fetthaltiger Mahlzeit für bessere Bioverfügbarkeit. Kakaobutter verlangsamt Absorption → gleichmäßigere Wirkung.', '⚠️ Bei Histaminintoleranz: Vorsicht. Bei Nierensteinen: Mit Kalzium kombinieren (Oxalatbindung).', '⚠️ "Prozent Kakao" ≠ Flavanolgehalt! Alkalisiertes (Dutch-processed) Kakaopulver hat 60-90% weniger Flavanole. Auf standardisierte Extrakte achten.', '500 mg Flavanole', 'omega-3, coenzym-q10, magnesium, vitamin-c', 'mao-hemmer', '0', '⛔ MAO-Hemmer: Hypertensive Krise durch Tyramin/PEA möglich! Additive Blutdrucksenkung mit Antihypertensiva.', 'Nein', 'Ja (Flavanole)', 'Ja', 'Ja', '⚠️ Moderater Konsum sicher. Koffein <200 mg/Tag. Yale-Studie: Schokolade kann Präeklampsie-Risiko um bis zu 70% senken.', '⚠️ Theobromin geht in Muttermilch über. Bei Säuglings-Irritabilität: Konsum reduzieren.', 'Ab 3 Jahren in moderaten Mengen. Koffein-/Theobromingehalt beachten.', '✅ Gut geeignet. COSMOS-Studie zeigte Nutzen bei ≥60/65-Jährigen.', '⚠️ KRITISCH: Auf Flavanol-Standardisierung achten (mind. 200 mg)! Cadmium-Zertifikat bei südamerikanischem Kakao. Nicht alkalisiert (Dutch-processed).', 'Monomere/Dimere gut absorbiert (2-5%). Procyanidine werden im Magen hydrolysiert. Metaboliten tragen zur Wirkung bei.', 'Standardisierter Kakaoextrakt mit mind. 200 mg Flavanolen pro Portion, inkl. Epicatechin-Angabe.', 'Kühl, trocken, lichtgeschützt. Flavanole oxidationsempfindlich.', '24', '⚠️ Theobromin: Bei >0,8-1,5 g/Tag Schwitzen, Zittern, Tachykardie. Cadmium-Kontamination (bes. Südamerika). Oxalate (Nierensteine). Histamin.', '⛔ MAO-Hemmer-Therapie. ⚠️ Schwere GERD. Histaminintoleranz. Kalziumoxalat-Nierensteine. Herzrhythmusstörungen.', 'GI-Beschwerden, Kopfschmerzen, Schlafstörungen (Koffein/Theobromin), allergische Reaktionen (selten).', 'Tachykardie, Tremor, Übelkeit, Erbrechen, Unruhe (bei sehr hohen Theobromin-Dosen >1 g).', 'Nein (außer bei Risikofaktoren)', '-', '-', 'Kakaobohnen (Theobroma cacao). Dunkle Schokolade (≥70% Kakao, nicht alkalisiert). Rohes Kakaopulver.', '200-500', 'mg Flavanole/Tag (EFSA: mind. 200 mg für Health Claim; COSMOS: 500 mg)', 'Nicht etabliert', '-', 'Keine spezifischen Höchstmengen für Flavanole. Cadmium-Grenzwerte: 0,1-0,8 mg/kg je nach Produkt.', 'Keine DGE-Referenzwerte für Kakaoflavanole.', '2025-12-24', 'VERIFIZIERT (COSMOS PMID 35294962; EFSA VO 851/2013; Cochrane PMID 28439881)'),
  ('coleus-forskohlii', 'Coleus forskohlii (Forskolin)', 'Coleus forskohlii (Forskolin)', 'Forskolin, Plectranthus barbatus, Buntnessel, Indian Coleus, Makandi, Forskohlii-Extrakt', 'Pflanzliche Extrakte', 'Gewichtsmanagement, Stoffwechsel, Kardiovaskulär', '⚠️ EFSA HEALTH CLAIM "ON HOLD" (ID 2248). Wirkmechanismus: Forskolin aktiviert Adenylatzyklase DIREKT → 35-fache cAMP-Erhöhung → Lipolyse, Thermogenese. RCT Godard 2005 (PMID 16129715, n=30 Männer): Signifikante Körperfettreduktion, erhöhtes freies Testosteron. Weitere Anwendungen: Glaukom (topisch), Asthma (inhalativ). ⛔ SCHWANGERSCHAFT KONTRAINDIZIERT (uterotone Wirkung)!', '⚠️ Körperfett (Männer, moderat); ⚠️ Testosteron ↑; ✅ Glaukom (topisch); ⛔ Schwangerschaft kontraindiziert', 'Gewichtsmanagement (adjunktiv), Körperzusammensetzung, Glaukom (topisch)', '⚠️ EFSA Health Claim ID 2248 "Körpergewichtsmanagement" ist ON HOLD seit 2012 (Teil der 1.548 botanischen Claims im Übergangsstatus). Nicht zugelassen, nicht abgelehnt.', '30 Minuten vor den Mahlzeiten einnehmen.', 'Lipidbasierte Formulierungen können Absorption verbessern (geringe Wasserlöslichkeit).', '⛔ NICHT mit Antihypertensiva ohne Überwachung. NICHT mit Antikoagulantien. NICHT in Schwangerschaft/Stillzeit.', '⚠️ Häufigste Nebenwirkung: Durchfall (81% aller NW). Langsam einschleichen. Bei GI-Beschwerden: Dosis reduzieren.', '250 mg Extrakt (10% = 25 mg Forskolin)', 'gruener-tee-extrakt, l-carnitin', 'antihypertensiva, antikoagulantien, schilddruesenmedikamente, nitrate', '0', '⛔ KRITISCHE INTERAKTIONEN: Additive Hypotonie mit Antihypertensiva. Erhöhtes Blutungsrisiko mit Antikoagulantien. CYP3A4-Induktion kann Medikamentenwirkung abschwächen!', 'Ja (Diterpen)', 'Nein (geringe Wasserlöslichkeit)', 'Ja', 'Ja', '⛔ ABSOLUTE KONTRAINDIKATION! Uterotone Wirkung, traditionelle Verwendung als Emmenagogum/Kontrazeptivum. Plazentare Toxizität in vitro.', '⛔ KONTRAINDIZIERT (unzureichende Sicherheitsdaten).', '⚠️ Keine Daten für Kinder. Nicht empfohlen.', '⚠️ Vor