INSERT INTO supplements_basis (id, name, name_en, auch_bekannt_als, kategorie, unterkategorie, wirkung, wirkung_kurz, symptome_ziele, health_claims_efsa, einnahme_zeitpunkt, einnahme_mit, einnahme_ohne, einnahme_hinweis, max_einzeldosis, kombiniert_gut_mit, nicht_zusammen_mit, zeitlicher_abstand_h, kombinations_hinweis, fettloeslich, wasserloeslich, vegan_verfuegbar, halalzertifiziert_moeglich, schwangerschaft, stillzeit, kinder_geeignet, senioren_hinweis, qualitaetsmerkmale, bioverfuegbarkeit_info, beste_form, lagerung, haltbarkeit_monate, warnhinweise, kontraindikationen, nebenwirkungen_ueberdosis, ueberdosis_symptome, bluttest_empfohlen, welcher_blutwert, optimalbereich, natuerliche_quellen, rda_erwachsene, rda_einheit, ul_efsa, ul_einheit, bfr_hoechstmenge, dge_referenz, letzte_aktualisierung, verifiziert) VALUES
  ('betain-hcl-ki', 'Betain-HCl (BEI GERD KONTRAINDIZIERT!)', 'Betaine HCl (CONTRAINDICATED in GERD!)', 'Betain-HCl, Betaine Hydrochloride, Trimethylglycin-Hydrochlorid, TMG-HCl', 'Saeure-Supplements', 'KONTRAINDIZIERT', 'ABSOLUT KONTRAINDIZIERT BEI GERD! Erhoeht Magensaeure drastisch (kann pH von 5,2 auf 0,6 senken in 30 Min). Aktiviert Pepsin (maximal schaedigend bei pH <3,0). Direkte Saeureschädigung des Oesophagus bei Reflux! FDA 1993: Aus OTC entfernt wegen fehlender Evidenz. WebMD: LIKELY UNSAFE bei Magengeschwuer. PeaceHealth: Grosse Mengen koennen Magenschleimhaut verbrennen!', 'ABSOLUT KONTRAINDIZIERT bei GERD! Erhoeht Saeure, aktiviert Pepsin!', 'NUR bei diagnostizierter Hypochlorhydrie (selten!) - NIEMALS bei GERD/Reflux!', 'KEINE zugelassenen EFSA Health Claims', '-', '-', '-', 'NIEMALS bei GERD, Reflux, Sodbrennen, Magengeschwuer, Barrett-Oesophagus verwenden!', '-', '-', '-', '-', '-', 'Nein', 'Ja', 'Ja (synthetisch)', 'Ja', 'Keine Daten - NICHT EMPFOHLEN', 'Keine Daten - NICHT EMPFOHLEN', 'NEIN', 'NEIN - gefaehrlich bei altersbedingtem Reflux!', '-', '-', '-', '-', '-', 'ABSOLUT KONTRAINDIZIERT: GERD, Reflux, Magengeschwuer, Barrett-Oesophagus, erosive Gastritis, NSAID-Einnahme!', 'GERD (absolut!), Reflux (absolut!), Magengeschwuer (absolut!), Barrett (absolut!), erosive Gastritis, H. pylori, NSAIDs', 'Sodbrennen, Magenbrennen, Uebelkeit, Mukosaverbrennungen!', 'Mukosaverbrennungen, starke Schmerzen, Geschwuerbildung', '-', '-', '-', '-', '-', '-', '-', '-', '-', '-', '2026-01-22', 'VERIFIZIERT - ABSOLUT KONTRAINDIZIERT BEI GERD'),
  ('pepsin-ki', 'Pepsin (BEI GERD KONTRAINDIZIERT!)', 'Pepsin (CONTRAINDICATED in GERD!)', 'Pepsin, Pepsinogen, Magen-Protease, EC 3.4.23.1', 'Enzyme', 'KONTRAINDIZIERT', 'ABSOLUT KONTRAINDIZIERT BEI GERD! Pepsin ist der PRIMAERE SCHAEDIGENDE FAKTOR bei Reflux! Tobey et al. (PMID 11721751): Saeure + Pepsin verursacht IRREVERSIBLE Laesionen innerhalb von 15 Minuten. Johnston et al. (PMC3216344): Pepsin adhäriert an Zellen, wird endozytiert, verursacht intrazellulären Schaden selbst bei pH 7,4. Kann durch saure Lebensmittel REAKTIVIERT werden!', 'ABSOLUT KONTRAINDIZIERT! Pepsin ist HAUPTURSACHE fuer Oesophagusschaeden bei Reflux!', 'NUR bei diagnostizierter Hypochlorhydrie (selten!) - NIEMALS bei GERD/Reflux!', 'KEINE zugelassenen EFSA Health Claims', '-', '-', '-', 'NIEMALS bei GERD, Reflux, Sodbrennen, Barrett-Oesophagus verwenden! Pepsin verursacht den Schaden!', '-', '-', '-', '-', '-', 'Nein', 'Ja', 'Teilweise (pilzliche Proteasen)', 'Teilweise', 'Keine Daten - NICHT EMPFOHLEN', 'Keine Daten - NICHT EMPFOHLEN', 'NEIN', 'NEIN - gefaehrlich!', '-', '-', '-', '-', '-', 'ABSOLUT KONTRAINDIZIERT: GERD, Reflux, Barrett-Oesophagus! Pepsin ist der HAUPTSCHADENSFAKTOR!', 'GERD (absolut!), Reflux (absolut!), Barrett (absolut!), erosive Oesophagitis, Laryngopharyngealer Reflux', 'Verstaerkt Oesophagusschaeden, kann Karzinogenese foerdern!', 'Irreversible Gewebeschaeden, Ulzeration', '-', '-', '-', '-', '-', '-', '-', '-', '-', '-', '2026-01-22', 'VERIFIZIERT - ABSOLUT KONTRAINDIZIERT (PMID 11721751, PMC3216344)'),
  ('apfelessig-ki', 'Apfelessig (BEI GERD KONTRAINDIZIERT!)', 'Apple Cider Vinegar (CONTRAINDICATED in GERD!)', 'Apfelessig, ACV, Apple Cider Vinegar, Essig', 'Saeure', 'KONTRAINDIZIERT', 'KONTRAINDIZIERT BEI GERD! pH ~2,5 (hochgradig sauer - aehnlich wie Magensaeure). KEINE klinischen Studien unterstuetzen ACV fuer GERD (Harvard Health, Cleveland Clinic, PMC6469461). Reaktiviert an Gewebe gebundenes Pepsin. Kann Zahnschmelz erodieren. Der alkalisierende Mythos ist FALSCH - die UNMITTELBARE Wirkung in Oesophagus und Magen ist hochgradig sauer!', 'KONTRAINDIZIERT! pH 2,5, keine Evidenz, reaktiviert Pepsin!', 'NICHT bei GERD/Reflux verwenden - keine Evidenz, potentieller Schaden!', 'KEINE zugelassenen EFSA Health Claims', '-', '-', '-', 'NIEMALS bei GERD/Reflux! Trotz Internet-Mythen KEINE Evidenz fuer Nutzen, nur Risiken!', '-', '-', '-', '-', '-', 'Nein', 'Ja', 'Ja', 'Ja', 'Keine Daten', 'Keine Daten', 'NEIN', 'NEIN', '-', '-', '-', '-', '-', 'KONTRAINDIZIERT bei GERD! Sauer (pH 2,5), reaktiviert Pepsin, erodiert Zahnschmelz!', 'GERD, Reflux, Sodbrennen, Barrett-Oesophagus, Zahnschmelzprobleme', 'Verstaerkt Reflux-Symptome, Zahnschmelzerosion, Oesophagusreizung', 'Schwere Oesophagusschaeden bei uebermaessigem Konsum', '-', '-', '-', '-', '-', '-', '-', '-', '-', '-', '2026-01-22', 'VERIFIZIERT - KONTRAINDIZIERT (keine Evidenz, potentieller Schaden)'),
  ('cynarin', 'Cynarin (1,3-Dicaffeoylchinasäure)', 'Cynarin / Cynarine / 1,3-Dicaffeoylquinic acid', '1,3-DCQA, 1,3-Dicaffeoylchinasäure, Artischocken-Wirkstoff', 'Polyphenole', 'caffeoylchinasaeuren', '⚠️⚠️ KRITISCH: ISOLIERTES CYNARIN IST AUF DEM EU-SUPPLEMENT-MARKT NICHT VERFÜGBAR! Alle ''Cynarin-Produkte'' sind Artischockenextrakte. Chemisch: Diester aus 2× Kaffeesäure + Chinasäure. CAS: 30964-13-7, MW: 516,45 g/mol. MISSVERSTÄNDNIS: Cynarin wurde historisch als ''Hauptwirkstoff'' der Artischocke bezeichnet - FALSCH! Chlorogensäure ist 67× häufiger (497 vs. 7,4 mg/100g). PHARMAKOKINETIK: Cynarin ist im Humanplasma NICHT NACHWEISBAR - wird zu Kaffeesäure hydrolysiert (PMID: 15693705). KLINISCHE EVIDENZ NEGATIV: Heckers 1977 (PMID: 576409) - 250-750mg Cynarin täglich KEINE Wirkung auf Cholesterin.', '⚠️ NICHT als Einzelsubstanz verfügbar! Nur Teil von Artischockenextrakt. Historisch überbewerteter ''Wirkstoff''.', 'gallenfluss (nur als Teil Artischockenextrakt)', '⛔ KEINE - Weder für isoliertes Cynarin noch für Artischocke sind EFSA Health Claims zugelassen!', 'Mit Mahlzeit (als Teil Artischockenextrakt)', '-', '⚠️ Bei Gallensteinen KONTRAINDIZIERT (wenn als Artischockenextrakt)', '⚠️⚠️ NICHT als isolierte Substanz supplementieren! Nur als Teil von Artischockenextrakt sinnvoll. ''Cynarin-standardisierte'' Extrakte enthalten trotzdem 67× mehr Chlorogensäure.', '-', 'chlorogensaeure, luteolin, cynaropikrin', '-', '-', 'Im natürlichen Artischockenextrakt mit anderen Caffeoylchinasäuren und Flavonoiden kombiniert.', 'Nein', 'Ja', 'Ja (pflanzlich)', 'Ja', 'Nicht empfohlen (keine Daten für isoliertes Cynarin)', 'Nicht empfohlen (keine Daten)', 'Nicht empfohlen', '-', '⚠️ Nur als Analytik-Referenzstandard erhältlich (Sigma-Aldrich: 166€/10mg, PhytoLab). KEIN Supplement-Produkt mit isoliertem Cynarin auf EU-Markt!', '⛔ NICHT BIOVERFÜGBAR: Cynarin ist im Humanplasma NICHT nachweisbar! Wird im GI-Trakt zu Kaffeesäure + Chinasäure hydrolysiert (PMID: 15693705).', '⭐ Artischockenextrakt verwenden (nicht isoliertes Cynarin) - standardisiert auf Caffeoylchinasäuren ≥5%', 'Kühl, dunkel, trocken', '24', '⚠️⚠️ NICHT ALS EINZELSUBSTANZ VERFÜGBAR! ⚠️ Gallenstein-Kontraindikation bei Artischockenextrakt beachten! ⚠️ Klinische Studie NEGATIV (PMID: 576409): Keine Cholesterinsenkung.', 'Gallensteine/Gallengangsverschluss (bei Artischockenextrakt), Asteraceae-Allergie', 'Als Teil von Artischockenextrakt: GI-Beschwerden möglich', 'Nicht anwendbar (nicht als Einzelsubstanz verfügbar)', 'Nein', '-', '-', 'Artischockenblätter (Cynara cardunculus) - aber nur 7,4 mg/100g vs. 497 mg/100g Chlorogensäure!', '-', '-', '-', '-', '-', 'Keine Referenzwerte - kein essentieller Nährstoff, nicht als Einzelsubstanz relevant', '2026-01-22', 'VERIFIZIERT'),
  ('nac-leber-formel', 'NAC-Leber-Formel (N-Acetylcystein für Hepatoprotektion)', 'NAC Liver Formula / N-Acetylcysteine for Liver Support', 'NAC, N-Acetylcystein, Acetylcystein, ACC (Arzneimittel), Glutathion-Precursor, Leber-NAC', 'Aminosäuren', 'cystein-derivate', 'NAC (CAS: 616-91-1, MW: 163,19 g/mol) ist der wichtigste Glutathion-Precursor für Leberschutz. HEPATOPROTEKTIVE MECHANISMEN: 1) Glutathion-Repletion (GSH-Synthese-Substrat), 2) Direkte ROS-Scavenging, 3) Anti-fibrotisch (TGF-β-Hemmung, HSC-Deaktivierung), 4) NF-κB-Hemmung (antiinflammatorisch). KLINISCHE EVIDENZ: ⭐⭐ NAFLD: 1200-2400mg/Tag senkt ALT signifikant (PMID: 22308119, 31460584). ⭐⭐⭐ Alkoholische Hepatitis: NAC+Prednisolon: 8% vs. 24% 1-Monats-Mortalität (NEJM, PMID: 22043968). ⭐⭐ Nicht-Paracetamol-DILI: Meta-Analysen zeigen verbesserte Überlebensrate (OR 2,85). ⭐ Zirrhose: 600mg/Tag verbessert Child-Pugh/MELD (PMID: 38313355).', '⭐⭐ Glutathion-Precursor; NAFLD-Evidenz; Alkohol. Hepatitis; Anti-fibrotisch; NF-κB-Hemmung', 'leberschutz, nafld, nash, fettleber, alkoholische hepatitis, hepatoprotektion, leberwerte', '⛔ KEINE zugelassenen EFSA Health Claims für NAC! (Weder Mukolyse noch Leberschutz)', 'Nüchtern oder mit Mahlzeit; 2-3× täglich verteilt für konstante GSH-Spiegel', 'Vitamin C (regeneriert GSH), Alpha-Liponsäure, Silymarin (synergistisch)', 'Aktivkohle (reduziert Absorption), Nitroglycerin (verstärkte Hypotonie!)', 'Für Leberschutz: 1200-1800 mg/Tag oral empfohlen (Studiendosen: bis 2400 mg/Tag). ⚠️ EU-Höchstmengen beachten: Spanien nur 300mg/Tag, NL/NO bis 1200mg/Tag erlaubt.', '600-1200 mg (je nach Landesrecht)', 'silymarin, alpha-liponsaeure, vitamin-c, cholin', 'nitroglycerin', '2h zu Aktivkohle', 'NAC + Silymarin: Synergistische Hepatoprotektion (verschiedene Mechanismen). NAC + ALA: Erweiterter antioxidativer Schutz. NAC + Cholin: Cholin hat EFSA-Claim für Leberfunktion!', 'Nein', 'Ja', 'Ja (synthetisch)', 'Ja', 'Nicht empfohlen (unzureichende Daten)', 'Nicht empfohlen (unzureiche